class Tagger:
    def __init__(self, token2id, id2tag, pad=True):
        self.token2id = token2id
        self.id2tag = id2tag
        self.unknown = '<UNK>'
        self.end_token = '<end>'

        self.pad = pad

    def label_tokens(self, sentence_tokens, **kwargs):
        unknown_token = self.unknown
        end_token = self.end_token
        result = []

        for token in sentence_tokens:
            if token in self.token2id.keys():
                result.append(self.token2id[token])
            else:
                result.append(self.token2id[unknown_token])

        if self.pad:
            padding_length = kwargs['padding_length']
            result += [0] * (padding_length - len(sentence_tokens))

        result.append(self.token2id[end_token])

        return result


    def tag_labels(self, label_tokens, **kwargs):
        pad = kwargs['pad']

        if pad:
            padding_length = kwargs['padding_length']
            tag_tokens = label_tokens.copy()
            if len(tag_tokens) < padding_length:
                for i in range(padding_length - len(tag_tokens)):
                    tag_tokens.append(0)
            label_tokens = tag_tokens.copy()
        else:
            padding_length = kwargs['labels_len']

        results = []
        for label in label_tokens:
            if label == 0:
                results.append('NULL')
            else:
                results.append(self.id2tag[label])

        return results


    def process_data(self, data, vocab_size, labels_map, vocab_file, labels_file):
        def tokenize(sent):
            return [self.end_token] + ['UNK' if w not in self.token2id.keys() else w for w in sent.split()] + [self.end_token]

        def update_word2id(file):
            with open(file, 'r', encoding='utf-8') as f:
                data = f.read()
                word2id = dict()
                for word in data.splitlines():
                    word2id[word] = 1

            return word2id

        def update_tag2id(file):
            with open(file, 'r', encoding='utf-8') as f:
                data = f.read()
                tag2id = dict()

                for tag in data.splitlines():
                    tag2id[tag] = 1
                    self.id2tag.append(tag)

            return tag2id


        if vocab_file:
            word2id = update_word2id(vocab_file)

        if labels_file:
            tag2id = update_tag2id(labels_file)

        return word2id, tag2id

